        Init,
        Run(b4, b5),
        Walk { foo: b5 },
        Boom,
    }

    #[kernel]
    fn do_stuff(a: Foo) -> (b8, b8, NooState, Foo) {
        let z = (a.b, a.a);
        let c = a;
        let q = signed::<4>(-2);
        let c = Red {
            x: bits::<4>(1),
            y: bits::<6>(2),
        };
        let d = Foo {
            a: bits::<8>(1),
            b: q,
            c,
        };
        let Foo { a: ar, b, c: _ } = d;
        let q = Bar(1, 2);
        let x = NooState::Run(bits::<4>(1), bits::<5>(2));
        let e = ar;
        (e, ar, x, d)
    }
    let inputs = [
