#[test]
fn test_adt_inference() {
    use rhdl_bits::alias::*;
    use rhdl_bits::bits;
    use rhdl_std::*;

    #[derive(PartialEq, Copy, Clone, Digital)]
    pub enum Red {
        A,
        B(b4),
        C { x: b4, y: b6 },
    }

    #[derive(PartialEq, Copy, Clone, Digital)]
    pub struct Foo {
        a: b8,
        b: s4,
        c: Red,
    }

    #[derive(PartialEq, Copy, Clone, Digital)]
    pub enum NooState {
        Init,
        Run(b4, b5),
        Walk { foo: b5 },
        Boom,
    }

    #[kernel]
    fn fifo(b: b8, a: b4) -> b8 {
        b
    }

    const MY_SPECIAL_NUMBER: b8 = bits(42);

    #[kernel]
    fn do_stuff(a: Foo, s: NooState) -> (NooState, b7) {
        let z = (a.b, a.a + MY_SPECIAL_NUMBER);
        let foo = bits::<12>(6);
        let foo2 = foo + foo;
        let c = a;
        let q = signed::<4>(2);
        let q = Foo {
            a: bits::<8>(1),
            b: q,
            c: Red::A,
        };
        let c = Red::A;
        let d = c;
        let z = fifo(bits::<8>(3), bits::<4>(5));
        let mut q = bits::<4>(1);
        let l = any::<4>(q);
        q = set_bit::<4>(q, 3, true);
        let p = get_bit::<4>(q, 2);
        let p = as_signed::<4>(q);
        if a.a > bits::<8>(12) {
            return (NooState::Boom, bits::<7>(3));
        }
        let e = Red::B(q);
        let x1 = bits::<4>(4);
        let y1 = bits::<6>(6);
        let mut ar = [bits::<4>(1), bits::<4>(1), bits::<4>(3)];
        ar[1] = bits::<4>(2);
        let z: [Bits<4>; 3] = ar;
        let q = ar[1];
        let f: [b4; 5] = [bits::<4>(1); 5];
        let h = f[2];
        let k = NooState::Init;
        let f = Red::C { y: y1, x: x1 };
        let d = match s {
            NooState::Init => NooState::Run(bits::<4>(1), bits::<5>(2)),
            NooState::Run(x, y) => NooState::Walk { foo: y + 3 },
            NooState::Walk { foo: x } => {
                let q = bits::<5>(1) + x;
                NooState::Boom
            }
            NooState::Boom => NooState::Init,
        };
        let k = 42;
        (d, bits::<7>(k))
    }

    let foos = [
        Foo {
            a: bits::<8>(1),
            b: signed::<4>(2),
            c: Red::A,
        },
        Foo {
            a: bits::<8>(1),
            b: signed::<4>(2),
            c: Red::B(bits::<4>(1)),
        },
        Foo {
            a: bits::<8>(1),
            b: signed::<4>(2),
            c: Red::C {
                x: bits::<4>(1),
                y: bits::<6>(2),
            },
        },
    ];
    let noos = [
        NooState::Init,
        NooState::Boom,
        NooState::Run(bits::<4>(1), bits::<5>(2)),
        NooState::Walk { foo: bits::<5>(3) },
    ];
    let inputs = iproduct!(foos.into_iter(), noos.into_iter()).collect::<Vec<_>>();
    test_kernel_vm_and_verilog::<do_stuff, _, _, _>(do_stuff, inputs.into_iter()).unwrap();
}

#[test]
fn test_adt_shadow() {
    #[derive(PartialEq, Copy, Clone, Digital)]
    pub enum NooState {
        Init,
        Run(u8, u8, u8),
        Walk { foo: u8 },
        Boom,
    }

    #[kernel]
    fn do_stuff(mut s: NooState) -> (u8, NooState) {
        let y = bits::<12>(72);
        let foo = bits::<14>(32);
        let mut a: u8 = 0;
        let d = match s {
            NooState::Init => {
                a = 1;
                NooState::Run(1, 2, 3)
            }
            NooState::Walk { foo: x } => {
                a = x;
                NooState::Boom
            }
            NooState::Run(x, _, y) => {
                a = x + y;
                NooState::Walk { foo: 7 }
            }
            NooState::Boom => {
                a = a + 3;
                NooState::Init
            }
        };
        (a, d)
    }
    let noos = [
        NooState::Init,
        NooState::Boom,
        NooState::Run(1, 2, 3),
        NooState::Walk { foo: 4 },
    ];
    test_kernel_vm_and_verilog::<do_stuff, _, _, _>(do_stuff, noos.into_iter().map(|x| (x,)))
        .unwrap();
}

#[test]
fn test_compile() {
    use rhdl_bits::alias::*;
    #[derive(PartialEq, Copy, Clone, Digital)]
    pub struct Foo {
        a: u8,
        b: u16,
        c: [u8; 3],
    }

    #[derive(PartialEq, Copy, Clone, Digital)]
    pub enum NooState {
        Init,
        Run(u8, u8, u8),
        Walk { foo: u8 },
        Boom,
    }

    const CONST_PATH: b4 = bits(4);
    #[kernel]
    fn do_stuff(mut a: Foo, mut s: NooState) -> Foo {
        let k = {
            bits::<12>(4) + 6;
            bits::<12>(6)
        };
        let mut a: Foo = a;
        let mut s: NooState = s;
        let q = if a.a > 0 {
            bits::<12>(3)
        } else {
            bits::<12>(0)
        };
        let y = bits::<12>(72);
        let t2 = (y, y);
        let q: u8 = 4;
        let z = a.c;
        let w = (a, a);
        a.c[1] = q + 3;
        a.c = [0; 3];
        a.c = [1, 2, 3];
        let q = (1, (0, 5), 6);
        let (q0, (q1, q1b), q2): (u8, (u8, u8), u16) = q; // Tuple destructuring
        a.a = 2 + 3 + q1;
        let z;
        if 1 > 3 {
            z = bits::<4>(2);
        } else {
            z = bits::<4>(5);
        }
        a.b = {
            7 + 9;
            5 + !8
        };
        a.a = if 1 > 3 {
            7
        } else {
            {
                a.b = 1;
                a.b = 4;
            }
            9
        };
        let g = 1 > 2;
        let h = 3 != 4;
        let mut i = g && h;
        if z == bits::<4>(3) {
            i = false;
        }
        match a {
            Foo {
                a: 1,
                b: 2,
                c: [1, 2, 3],
            } => {}
            Foo {
                a: 3,
                b: 4,
                c: [1, 2, 3],
            } => {}
            _ => {}
        }
        let c = bits::<4>(match z {
            CONST_PATH => 1,
            Bits::<4>(1) => 2,
            Bits::<4>(2) => 3,
            Bits::<4>(3) => {
                a.a = 4;
                4
            }
            _ => 6,
        });
        let d = match s {
            NooState::Init => {
                a.a = 1;
                NooState::Run(1, 2, 3)
            }
            NooState::Walk { foo: x } => {
                a.a = x;
                NooState::Boom
            }
            NooState::Run(x, t, y) => {
                a.a = x + y;
                NooState::Walk { foo: 7 }
            }
            NooState::Boom => {
                a.a += 3;
                NooState::Init
            }
        };
        a
    }
    let foos = [
        Foo {
            a: 1,
            b: 2,
            c: [1, 2, 3],
        },
        Foo {
            a: 4,
            b: 5,
            c: [4, 5, 6],
        },
    ];
    let noos = [
        NooState::Init,
        NooState::Boom,
        NooState::Run(1, 2, 3),
        NooState::Walk { foo: 4 },
    ];
    let inputs = iproduct!(foos.into_iter(), noos.into_iter()).collect::<Vec<_>>();
    test_kernel_vm_and_verilog::<do_stuff, _, _, _>(do_stuff, inputs.into_iter()).unwrap();
}

