#[test]
fn test_fn_name_stuff() {
    // There are 2 namespaces (type and value).
    // A function is a value.  So this is legal:

    struct add_stuff {}

    impl add_stuff {
        fn args() -> Vec<Kind> {
            vec![Kind::make_bits(8), Kind::make_bits(8)]
        }
        fn ret() -> Kind {
            Kind::make_bits(8)
        }
    }

    fn add_stuff(a: u8, b: u8) -> u8 {
        a + b
    }

    assert_eq!(add_stuff(3_u8, 4_u8), 7_u8);
    assert_eq!(
        add_stuff::args(),
